        "    fig, axes = plt.subplots(4, n, figsize=(n*2, 8))\n",
        "    eps = 0.03\n",
        "    img_batch = images[:n].to(device)\n",
        "    lbl_batch = labels[:n].to(device)\n",
        "    samples = {\n",
        "        'Clean': img_batch,\n",
        "        'Noise': noise_attack(model, img_batch, eps),\n",
        "        'FGSM':  fgsm_attack(model, img_batch, lbl_batch, eps),\n",
        "        'PGD':   pgd_attack(model, img_batch, lbl_batch, eps),\n",
        "    }\n",
        "    for row_idx, (name, adv) in enumerate(samples.items()):\n",
        "        with torch.no_grad():\n",
        "            preds = model(adv).argmax(1)\n",
        "        imgs_np = denormalize(adv).cpu().permute(0,2,3,1).numpy()\n",
        "        for col_idx in range(n):\n",
        "            ax = axes[row_idx, col_idx]\n",
        "            ax.imshow(imgs_np[col_idx].clip(0,1))\n",
        "            pred_lbl = CLASSES[preds[col_idx]]\n",
        "            true_lbl = CLASSES[lbl_batch[col_idx]]\n",
        "            color = 'green' if pred_lbl == true_lbl else 'red'\n",
        "            ax.set_title(pred_lbl, fontsize=8, color=color)\n",
        "            if col_idx == 0:\n",
        "                ax.set_ylabel(name, fontsize=9)\n",
        "            ax.axis('off')\n",
        "    plt.suptitle('Adversarial Examples (ε=0.03)  |  Green=Correct  Red=Fooled', fontsize=11)\n",
        "    plt.tight_layout()\n",
        "    plt.savefig('adversarial_examples.png', dpi=150)\n",
        "    save_to_drive('adversarial_examples.png')\n",
        "    plt.show()\n",
        "sample_images, sample_labels = next(iter(testloader))\n",
