        "VIT_EPOCHS = 100\n",
        "vit_criterion = nn.CrossEntropyLoss(label_smoothing=0.1)\n",
        "vit_optimizer = optim.AdamW(vit_model.parameters(), lr=1e-3,\n",
        "                            weight_decay=0.05, betas=(0.9, 0.999))\n",
        "def lr_lambda(epoch):\n",
        "    warmup = 10\n",
        "    if epoch < warmup:\n",
        "        return (epoch + 1) / warmup\n",
        "    progress = (epoch - warmup) / (VIT_EPOCHS - warmup)\n",
        "    return 0.5 * (1 + np.cos(np.pi * progress))\n",
        "\n",
        "vit_scheduler = optim.lr_scheduler.LambdaLR(vit_optimizer, lr_lambda)\n",
        "vit_history = {'train_acc': [], 'test_acc': []}\n",
        "best_vit_acc = 0.0\n",
        "\n",
        "for epoch in range(1, VIT_EPOCHS + 1):\n",
        "    tr_loss, tr_acc = train_epoch(vit_model, vit_trainloader,\n",
        "                                  vit_optimizer, vit_criterion, vit_scheduler)\n",
        "    te_acc = evaluate(vit_model, vit_testloader)\n",
        "    vit_history['train_acc'].append(tr_acc)\n",
        "    vit_history['test_acc'].append(te_acc)\n",
        "\n",
        "    if te_acc > best_vit_acc:\n",
        "        best_vit_acc = te_acc\n",
